/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(PurchTable, PurchLine), FormDataSourceEventType::Activated)]
public static void PurchLine_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    if(curExt() == "O014")
    {
        FormRun formRun = sender.formRun();

        FormStringControl itemSalesTaxGroup = formRun.design().controlName(formControlStr(PurchTable, LineSalesTax_TaxItemGroup));
        FormStringControl salesTaxGroup = formRun.design().controlName(formControlStr(PurchTable, LineSalesTax_TaxGroup));

        itemSalesTaxGroup.mandatory(true);
        salesTaxGroup.mandatory(true);
    }
}

